#[test]
fn set_mode_bogus_activation_mode_is_error() {
    let result = serde_json::from_str::<ControlRequest>(
        r#"{"cmd":"set_mode","args":{"mode":"bogus"}}"#,
    );
    assert!(result.is_err(), "expected Err for unknown ActivationMode, got: {result:?}");
}

